"""Generates a C++ header to load an XLA CompilationResult proto."""

from absl import app
from absl import flags

_PB_PATH = flags.DEFINE_string(
    "pb_path", None, "Runtime path to the protobuf file", required=True
)
_OUTPUT_H = flags.DEFINE_string(
    "output_h", None, "Output header file", required=True
)
_MODEL_FACTORY_NAME = flags.DEFINE_string(
    "model_factory_name",
    None,
    "Full name for the generated function",
    required=True,
)


def main(argv):
  if len(argv) > 1:
    raise app.UsageError("Too many command-line arguments.")

  # Generate include guard
  guard = (
      _OUTPUT_H.value.replace("/", "_")
      .replace(".", "_")
      .replace("-", "_")
      .upper()
      + "_"
  )

  header_content = f"""/* Generated by generate_aot_header.py */
#ifndef {guard}
#define {guard}

#include <memory>
#include <string>
#include <utility>

#include "absl/status/statusor.h"
#include "absl/status/status.h"
#include "absl/strings/str_cat.h"
#include "absl/strings/string_view.h"
#include "third_party/tensorflow/compiler/xla/backends/cpu/lite_aot/xla_aot_function.h"
#include "third_party/tensorflow/compiler/xla/service/cpu/executable.pb.h"
#include "third_party/tensorflow/tsl/platform/env.h"
#include "third_party/tensorflow/tsl/platform/path.h"
#include "third_party/tensorflow/tsl/platform/status.h"

namespace xla::cpu {{

inline absl::StatusOr<std::unique_ptr<XlaAotFunction>> {_MODEL_FACTORY_NAME.value}(
    absl::string_view pb_path = "{_PB_PATH.value}") {{
  CompilationResultProto proto;
  absl::Status read_status = tsl::ReadBinaryProto(tsl::Env::Default(), std::string(pb_path), &proto);
  if (!read_status.ok()) {{
      return absl::InternalError(
          absl::StrCat("Failed to read AOT compilation result proto for {_MODEL_FACTORY_NAME.value} from ",
                       pb_path, ": ", read_status.message()));
  }}
  return XlaAotFunction::Create(std::move(proto));
}}

}}  // namespace xla::cpu

#endif  // {guard}
"""

  with open(_OUTPUT_H.value, "w") as f:
    f.write(header_content)


if __name__ == "__main__":
  app.run(main)
